import React, { useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import { useNavigate } from 'react-router-dom';
import { createGroup, fetchMyGroups } from '../redux/thunks/groupThunks';
import { toast } from 'react-toastify';
import './CreateGroup.css';

const CreateGroup = () => {
  const [groupName, setGroupName] = useState('');
  const [groupDescription, setGroupDescription] = useState('');
  const [selectedImage, setSelectedImage] = useState(null);
  const [imagePreview, setImagePreview] = useState(null);
  const { loading } = useSelector((state) => state.groups);
  const dispatch = useDispatch();
  const navigate = useNavigate();

  const handleImageSelect = (e) => {
    const file = e.target.files?.[0];
    if (!file) return;
    setSelectedImage(file);
    const reader = new FileReader();
    reader.onload = () => setImagePreview(reader.result);
    reader.readAsDataURL(file);
  };

  const handleSubmit = async () => {
    if (!groupName.trim()) {
      toast.warn('Please enter a group name');
      return;
    }
    const result = await dispatch(createGroup({
      name: groupName.trim(),
      description: groupDescription.trim(),
      isPrivate: false,
    }));
    if (!result.error) {
      toast.success('Group created!');
      dispatch(fetchMyGroups());
      navigate('/groups');
    } else {
      toast.error(result.payload || 'Failed to create group');
    }
  };

  return (
    <div className="create-group-page">
      <div className="create-group-header">
        <button className="create-group-back" onClick={() => navigate('/groups')}>
          ←
        </button>
        <h1 className="create-group-title">Create Group</h1>
      </div>

      {/* Group icon */}
      <div className="create-group-icon-section">
        <label className="create-group-icon-label">
          {imagePreview ? (
            <img src={imagePreview} alt="Group" className="create-group-icon-img" />
          ) : (
            <div className="create-group-icon-placeholder">👥</div>
          )}
          <input type="file" accept="image/*" onChange={handleImageSelect} hidden />
        </label>
      </div>

      {/* Form */}
      <div className="create-group-form">
        <div className="create-group-field">
          <input
            type="text"
            className="create-group-input"
            placeholder="Enter Group Name"
            value={groupName}
            onChange={(e) => setGroupName(e.target.value)}
          />
        </div>
        <div className="create-group-field">
          <textarea
            className="create-group-textarea"
            placeholder="Enter Group Description"
            value={groupDescription}
            onChange={(e) => setGroupDescription(e.target.value)}
            rows={4}
          />
        </div>
        <button
          className="create-group-submit"
          onClick={handleSubmit}
          disabled={loading}
        >
          {loading ? 'Creating...' : 'Done'}
        </button>
      </div>
    </div>
  );
};

export default CreateGroup;
